import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import { addNotification } from "../notificationReducer";
import Modal from "../components/Modal";

function Enrollments() {
  const [enrollments, setEnrollments] = useState([]);
  const [courses, setCourses] = useState([]);
  const [files, setFiles] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState("");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [enrollmentToDelete, setEnrollmentToDelete] = useState(null);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();

  useEffect(() => {
    fetch(`http://localhost:3001/enrollments?studentId=${user.id}`)
      .then((res) => res.json())
      .then((data) => setEnrollments(data));
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(data));
    fetch("http://localhost:3001/files")
      .then((res) => res.json())
      .then((data) => setFiles(data));
  }, [user.id]);

  async function handleEnroll(e) {
    e.preventDefault();
    if (!selectedCourse) {
      toast.error("Please select a course.");
      return;
    }

    const newEnrollment = { studentId: user.id, courseId: selectedCourse };

    const response = await fetch("http://localhost:3001/enrollments", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(newEnrollment),
    });

    if (response.ok) {
      const enrollment = await response.json();
      setEnrollments([...enrollments, enrollment]);
      const courseName = courses.find(c => c.id === selectedCourse)?.name;
      dispatch(addNotification({
        id: Date.now(),
        userId: user.id,
        message: `Enrolled in ${courseName}!`,
        createdAt: new Date().toISOString(),
      }));
      await fetch("http://localhost:3001/notifications", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          userId: user.id,
          message: `Enrolled in ${courseName}!`,
          createdAt: new Date().toISOString(),
        }),
      });
      toast.success("Enrolled successfully!");
    } else {
      toast.error("Failed to enroll");
    }
  }

  async function handleUnenroll() {
    const response = await fetch(`http://localhost:3001/enrollments/${enrollmentToDelete}`, {
      method: "DELETE",
    });
    if (response.ok) {
      setEnrollments(enrollments.filter(e => e.id !== enrollmentToDelete));
      toast.success("Unenrolled successfully!");
    } else {
      toast.error("Failed to unenroll");
    }
    setIsModalOpen(false);
  }

  function openModal(enrollmentId) {
    setEnrollmentToDelete(enrollmentId);
    setIsModalOpen(true);
  }

  return (
    <div className="page-container">
      <h1>My Enrollments (Students Only)</h1>
      {user.role === "student" && (
        <div className="form-container">
          <div className="form-container">
            <select
              value={selectedCourse}
              onChange={(e) => setSelectedCourse(e.target.value)}
            >
              <option value="">-- Choose a course --</option>
              {courses.map((course) => (
                <option key={course.id} value={course.id}>
                  {course.name}
                </option>
              ))}
            </select>
            <button onClick={handleEnroll}>Enroll</button>
          </div>
        </div>
      )}
      <ul>
        {enrollments.map((enrollment) => (
          <li key={enrollment.id}>
            Course: {courses.find(c => c.id === enrollment.courseId)?.name || "Unknown"}
            <button onClick={() => openModal(enrollment.id)}>Unenroll</button>
            <ul>
              {files
                .filter(f => f.courseId === enrollment.courseId)
                .map(f => (
                  <li key={f.id}>
                    <a href={`http://localhost:3002${f.filePath}`} download>{f.fileName}</a>
                  </li>
                ))}
            </ul>
          </li>
        ))}
      </ul>
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={handleUnenroll}
        message="Are you sure you want to unenroll from this course?"
      />
    </div>
  );
}

export default Enrollments;
